import{_ as l,p as i,q as e,a1 as a}from"./framework-e0dd9823.js";const t={},o=a('<h1 id="情态动词" tabindex="-1"><a class="header-anchor" href="#情态动词" aria-hidden="true">#</a> 情态动词</h1><p>情态动词主要跟动词原型构成符合谓语，主谓宾和主系表都可以出现情态动词，因此一般有两个句型：</p><ol><li>主语 + 情态动词 + 实义动词原型 + （宾语） + 复合谓语</li><li>主语 + 情态动词 + be + 表语</li></ol><p>变一般疑问句：把情态动词移到开头；变否定句：直接在情态动词后面加 not 即可。</p><h2 id="常见的情态动词及其用法" tabindex="-1"><a class="header-anchor" href="#常见的情态动词及其用法" aria-hidden="true">#</a> 常见的情态动词及其用法</h2><h3 id="can" tabindex="-1"><a class="header-anchor" href="#can" aria-hidden="true">#</a> Can</h3><p>can 可以表示现在或者将来的情况。这两个时态时态都用 can 原型，不同时态加不同的时间状语即可。</p><p>用法：</p><ol><li>表示能力，有能力做某事</li></ol><ul><li>I can buy a bouse in the future.</li><li>I can buy a house now.</li><li>I can eat meat every day.</li><li>He can earn one million yuan a year.</li><li>She can take care of herself.</li></ul><ol start="2"><li>表示可能性，可能会做某事</li></ol><ul><li>Can you help me?</li><li>I am sorry, I can&#39;t go with you.</li></ul><ol start="3"><li>表示猜测，常用于否定句和疑问句，意思为“不可能...；可能...”</li></ol><ul><li>That can&#39;t be Mary, she is in hospital.</li><li>Can he still be alive after all these years?</li></ul><ol start="4"><li>表示许可，允许做某事</li></ol><ul><li>You can park here.</li><li>She can pick my mangoes.</li><li>You can&#39;t smoke here.</li></ul><h3 id="could" tabindex="-1"><a class="header-anchor" href="#could" aria-hidden="true">#</a> Could</h3><ol><li>Could 是 can 的过去式，用于表示过去发生的情况。</li></ol><ul><li>I can eat three bowls of rice.</li><li>I could eat three bowls of rice ten years ago.</li></ul><ol start="2"><li>表示礼貌</li></ol><ul><li>Could you show me the way?</li><li>Could I stay tonight?</li><li>Could I speak to you in private?</li></ul><h3 id="may" tabindex="-1"><a class="header-anchor" href="#may" aria-hidden="true">#</a> May</h3><p>may 和 can 的意思相近，may 也可以现在和将来时态。</p><p>用法：</p><ol><li>用于征求他人的意见，译为“可不可以”，一般用于一般疑问句，主语为“I”。</li></ol><ul><li>May I use your phone?</li><li>May I come in?</li><li>May I come around in the afternoon?</li><li>May I stay here?</li><li>May I call you tomorrow?</li><li>May I be your partner?</li><li>May I be your boyfriend?</li></ul><ol start="2"><li>表示允许做某事，用于陈述句。</li></ol><ul><li>You may park here.</li><li>You may not take photos in the museum.</li></ul><ol start="3"><li>表示可能，猜测，译为“也许”。</li></ol><ul><li>Anna may know Tom&#39;s address.</li><li>Jack may know Lily&#39;s secret.</li><li>He may have gone abroad.</li><li>They may be waiting at the station.</li></ul><ol start="4"><li>表示祝福</li></ol><ul><li>May you be happy!</li><li>May God be with you!</li><li>May you succeed!</li><li>May you have a good time!</li><li>May she rest in peace.</li></ul><h3 id="might" tabindex="-1"><a class="header-anchor" href="#might" aria-hidden="true">#</a> Might</h3><ol><li>Might 是 May 的过去式。</li></ol><ul><li>Jack may know Tom&#39;s address.</li><li>Jack might know Tom&#39;s address yesterday.</li></ul><ol start="2"><li>may 礼貌用法</li></ol><ul><li>May I go with you?</li><li>Might I go with you?</li></ul><h2 id="must" tabindex="-1"><a class="header-anchor" href="#must" aria-hidden="true">#</a> Must</h2><ol><li>表示必要或者很重要，译为“必须做某事”</li></ol><ul><li>You must learn English.</li><li>I must earn money.</li><li>I must go now.</li></ul><p>注意：must 否定句要用 have to 的否定格式</p><ul><li><p>You don&#39;t have to learn English.</p></li><li><p>Must we finish the homework today?</p></li><li><p>Yes, you must.</p></li><li><p>No, you don&#39;t have to.</p></li></ul><ol start="2"><li>mustn&#39;t 禁止做某事</li></ol><ul><li>You mustn&#39;t take pictures here, it&#39;s forbidden.</li><li>You mustn&#39;t drive without a license.</li></ul><ol start="3"><li>表示推测</li></ol><ul><li>You must be hungry.</li><li>They must be twins.</li></ul><h2 id="have-to" tabindex="-1"><a class="header-anchor" href="#have-to" aria-hidden="true">#</a> Have to</h2><p>have to 和 must 差不多，但是 must 强调说话人的意愿，have to 表示客观上的必要性。</p><p>一般现在时态：</p><ul><li>We have to help him.</li><li>We don&#39;t have to help him.</li><li>Do you have to help him.</li><li>My students have to be careful.</li><li>My students don&#39;t have to be careful.</li><li>She has to take pills.</li><li>She doesn&#39;t have to take pills.</li><li>Does she have to take pills.</li><li>The girl has to be careful.</li><li>The girl doesn&#39;t have to be careful.</li></ul><p>一般过去时态：</p><ul><li>They had to jump into th river last night.</li><li>They didn&#39;t have to jump into the river last night.</li><li>Did they have to jump into the river last?</li><li>You had to be careful yesterday.</li><li>You didn&#39;t have to be careful yesterday.</li></ul><p>一般将来时态:</p><ul><li>We will have to take the bus tomorrow.</li><li>We won&#39;t have to take the bus tomorrow.</li><li>Will you have to take the bus tomorrow.</li><li>You will have to be careful in the future.</li></ul><h2 id="其他" tabindex="-1"><a class="header-anchor" href="#其他" aria-hidden="true">#</a> 其他</h2><p>Ought to 应该</p><p>Should 应该</p><p>Dare 敢于</p><p>Be able to 能够</p><p>Need 需要</p><p>Had better 最好</p>',61),h=[o];function r(u,s){return i(),e("div",null,h)}const d=l(t,[["render",r],["__file","verb2.html.vue"]]);export{d as default};
